import React, { useCallback, useEffect, useLayoutEffect, useRef, useState } from 'react';
import { createPortal } from 'react-dom';
import { ArrowRight, Clapperboard, Film, FolderPlus, ImageIcon, Layers, Loader2, Music2, RefreshCw, Scissors, Trash2, Type, X } from 'lucide-react';
import { cn } from '@/shared/components/ui/contracts/cn';
import type { Shot } from '@/domains/generation/types';
import { usePortalMousedownGuard } from '@/shared/hooks/usePortalMousedownGuard';
import { WaveformOverlay } from '@/tools/video-editor/components/TimelineEditor/WaveformOverlay';
import { useWaveformData } from '@/tools/video-editor/hooks/useWaveformData';
import type { ClipMeta } from '@/tools/video-editor/lib/timeline-data';
import type { TimelineAction } from '@/tools/video-editor/types/timeline-canvas';

interface ContextMenuState {
  x: number;
  y: number;
  clientX: number;
}

interface ClipActionProps {
  action: TimelineAction;
  clipMeta: ClipMeta;
  isSelected: boolean;
  isPrimary?: boolean;
  isInPinnedShotGroup?: boolean;
  selectedClipIds?: string[];
  thumbnailSrc?: string;
  audioSrc?: string;
  clipWidth?: number;
  onSelect: (clipId: string, trackId: string) => void;
  onDoubleClickAsset?: (assetKey: string) => void;
  onDoubleClickVideoClip?: (clipId: string) => void;
  onSplitHere?: (clipId: string, clientX: number) => void;
  onSplitClipsAtPlayhead?: (clipIds: string[]) => void;
  onDeleteClip?: (clipId: string) => void;
  onDeleteClips?: (clipIds: string[]) => void;
  onToggleMuteClips?: (clipIds: string[]) => void;
  isVideoClip?: boolean;
  isTaskActive?: boolean;
  /** True when the clip's file no longer matches the generation's current primary variant */
  isVariantStale?: boolean;
  /** True when the clip is linked to a generation (enables "Update to current variant" in menu) */
  isGenerationAsset?: boolean;
  onUpdateVariant?: () => void;
  onDismissStale?: () => void;
  canCreateShotFromSelection?: boolean;
  existingShots?: Shot[];
  onCreateShotFromSelection?: () => Promise<Shot | null>;
  onGenerateVideoFromSelection?: () => void | Promise<void>;
  onNavigateToShot?: (shot: Shot) => void;
  onOpenGenerateVideo?: (shot: Shot) => void;
  isCreatingShot?: boolean;
}

const menuItemClassName = 'relative flex w-full cursor-default select-none items-center gap-2 rounded-sm px-2 py-1.5 text-sm outline-none transition-colors hover:bg-accent hover:text-accent-foreground';
const destructiveMenuItemClassName = `${menuItemClassName} hover:bg-destructive hover:text-destructive-foreground`;
const disabledMenuItemClassName = 'disabled:cursor-wait disabled:opacity-60';

type ClipContextMenuProps = Pick<ClipActionProps, 'isGenerationAsset' | 'onUpdateVariant' | 'isVariantStale' | 'onDismissStale' | 'onSplitHere' | 'onToggleMuteClips' | 'onSplitClipsAtPlayhead' | 'onCreateShotFromSelection' | 'onGenerateVideoFromSelection' | 'onNavigateToShot' | 'onOpenGenerateVideo' | 'isCreatingShot' | 'onDeleteClip' | 'onDeleteClips' | 'isInPinnedShotGroup'> & { actionId: string; contextMenu: ContextMenuState; menuRef: React.RefObject<HTMLDivElement | null>; closeMenu: () => void; hasBatchSelection: boolean; selectedClipIds: string[]; showShotActions: boolean; hasActionsBeforeShotSection: boolean; existingShots?: Shot[]; };
type ClipContextMenuItemProps = { icon: React.ComponentType<{ className?: string }>; onClick: () => void; children: React.ReactNode; disabled?: boolean; destructive?: boolean; suffix?: React.ReactNode; };

function ClipContextMenuItem({ icon: Icon, onClick, children, disabled = false, destructive = false, suffix }: ClipContextMenuItemProps) {
  return (
    <button
      type="button"
      className={cn(destructive ? destructiveMenuItemClassName : menuItemClassName, disabled && disabledMenuItemClassName)}
      onClick={onClick}
      disabled={disabled}
    >
      <Icon className="h-4 w-4" />
      {children}
      {suffix}
    </button>
  );
}

function ClipContextMenu(props: ClipContextMenuProps) {
  const [adjusted, setAdjusted] = useState<{ x: number; y: number } | null>(null);
  const [createdShot, setCreatedShot] = useState<Shot | null>(null);
  const [isCreatingLocal, setIsCreatingLocal] = useState(false);
  const { onCreateShotFromSelection } = props;

  // Recompute position whenever the menu's size changes (e.g. async-loaded
  // shots arrive, or "Create Shot" expands the menu) so it never overflows
  // the viewport. Falls back to a one-shot measurement if ResizeObserver
  // isn't available.
  useLayoutEffect(() => {
    const node = props.menuRef.current;
    if (!node) {
      setAdjusted(null);
      return;
    }

    const recompute = () => {
      const rect = node.getBoundingClientRect();
      const pad = 8;
      const viewportWidth = window.innerWidth;
      const viewportHeight = window.innerHeight;

      let x = props.contextMenu.x;
      if (x + rect.width + pad > viewportWidth) {
        x = Math.max(pad, viewportWidth - rect.width - pad);
      }

      let y = props.contextMenu.y;
      if (y + rect.height + pad > viewportHeight) {
        // Try flipping above the click point first; clamp if there's no room.
        const flipped = props.contextMenu.y - rect.height;
        y = flipped >= pad ? flipped : Math.max(pad, viewportHeight - rect.height - pad);
      }

      setAdjusted({ x, y });
    };

    recompute();

    if (typeof ResizeObserver === 'undefined') {
      return;
    }
    const observer = new ResizeObserver(recompute);
    observer.observe(node);
    return () => observer.disconnect();
  }, [props.contextMenu.x, props.contextMenu.y, props.menuRef]);

  usePortalMousedownGuard(props.menuRef);

  const handleCreateShot = useCallback(async () => {
    if (!onCreateShotFromSelection) return;
    setIsCreatingLocal(true);
    const shot = await onCreateShotFromSelection();
    setIsCreatingLocal(false);
    if (shot) {
      setCreatedShot(shot);
    }
  }, [onCreateShotFromSelection]);

  const pos = adjusted ?? props.contextMenu;
  const visibleExistingShots = (props.existingShots ?? []).filter((shot) => shot.id !== createdShot?.id);
  const hasAssetStateActions = !props.hasBatchSelection && Boolean(
    (props.isGenerationAsset && props.onUpdateVariant)
    || (props.isVariantStale && props.onDismissStale),
  );
  const hasLowerShotActions = Boolean(
    (!createdShot && (props.onCreateShotFromSelection || props.onGenerateVideoFromSelection))
    || (createdShot && (props.onNavigateToShot || props.onOpenGenerateVideo)),
  );

  return createPortal(
    <div
      ref={props.menuRef}
      className="fixed z-50 min-w-[10rem] overflow-hidden rounded-md border bg-popover p-1 text-popover-foreground shadow-md animate-in fade-in-0 zoom-in-95"
      style={{ left: pos.x, top: pos.y, visibility: adjusted ? 'visible' : 'hidden' }}
    >
      {!props.hasBatchSelection && props.isGenerationAsset && props.onUpdateVariant && (
        <ClipContextMenuItem icon={RefreshCw} onClick={() => { props.onUpdateVariant?.(); props.closeMenu(); }}>
          Update to current variant
        </ClipContextMenuItem>
      )}
      {!props.hasBatchSelection && props.isVariantStale && props.onDismissStale && (
        <ClipContextMenuItem icon={X} onClick={() => { props.onDismissStale?.(); props.closeMenu(); }}>
          Dismiss reminder
        </ClipContextMenuItem>
      )}
      {hasAssetStateActions && !props.isInPinnedShotGroup && (
        <div className="my-1 h-px bg-border" />
      )}
      {!props.isInPinnedShotGroup && (
        <>
          {!props.hasBatchSelection && props.onSplitHere && (
            <ClipContextMenuItem icon={Scissors} onClick={() => { props.onSplitHere?.(props.actionId, props.contextMenu.clientX); props.closeMenu(); }}>
              Split Here
            </ClipContextMenuItem>
          )}
          {props.hasBatchSelection && props.onToggleMuteClips && (
            <ClipContextMenuItem icon={Music2} onClick={() => { props.onToggleMuteClips?.(props.selectedClipIds); props.closeMenu(); }}>
              Mute/Unmute {props.selectedClipIds.length} clips
            </ClipContextMenuItem>
          )}
          {props.hasBatchSelection && props.onSplitClipsAtPlayhead && (
            <ClipContextMenuItem icon={Scissors} onClick={() => { props.onSplitClipsAtPlayhead?.(props.selectedClipIds); props.closeMenu(); }}>
              Split {props.selectedClipIds.length} clips at playhead
            </ClipContextMenuItem>
          )}
          {props.showShotActions && props.hasActionsBeforeShotSection && <div className="my-1 h-px bg-border" />}
          {props.showShotActions && visibleExistingShots.map((shot) => (
            <div key={shot.id} className="flex w-full items-center gap-1 rounded-sm px-2 py-1.5 text-sm">
              <span className="min-w-0 flex-1 truncate">{shot.name}</span>
              {props.onOpenGenerateVideo && (
                <button type="button" className="flex h-5 w-5 shrink-0 items-center justify-center rounded hover:bg-accent hover:text-accent-foreground" onClick={() => { props.onOpenGenerateVideo?.(shot); props.closeMenu(); }} title="Generate Video">
                  <Clapperboard className="h-3.5 w-3.5" />
                </button>
              )}
              {props.onNavigateToShot && (
                <button type="button" className="flex h-5 w-5 shrink-0 items-center justify-center rounded hover:bg-accent hover:text-accent-foreground" onClick={() => { props.onNavigateToShot?.(shot); props.closeMenu(); }} title="Jump to shot">
                  <ArrowRight className="h-3.5 w-3.5" />
                </button>
              )}
            </div>
          ))}
          {props.showShotActions && visibleExistingShots.length > 0 && hasLowerShotActions && (
            <div className="my-1 h-px bg-border" />
          )}
          {props.showShotActions && !createdShot && props.onCreateShotFromSelection && (
            <ClipContextMenuItem icon={FolderPlus} onClick={() => void handleCreateShot()} disabled={isCreatingLocal || props.isCreatingShot}>
              {isCreatingLocal ? 'Creating…' : 'Create Shot'}
            </ClipContextMenuItem>
          )}
          {props.showShotActions && createdShot && props.onNavigateToShot && (
            <ClipContextMenuItem icon={ArrowRight} onClick={() => { props.onNavigateToShot?.(createdShot); props.closeMenu(); }}>
              Jump to {createdShot.name}
            </ClipContextMenuItem>
          )}
          {props.showShotActions && createdShot && props.onOpenGenerateVideo && (
            <ClipContextMenuItem icon={Clapperboard} onClick={() => { props.onOpenGenerateVideo?.(createdShot); props.closeMenu(); }}>
              Generate Video
            </ClipContextMenuItem>
          )}
          {props.showShotActions && !createdShot && props.onGenerateVideoFromSelection && (
            <ClipContextMenuItem icon={Clapperboard} onClick={() => { props.closeMenu(); void props.onGenerateVideoFromSelection?.(); }} disabled={props.isCreatingShot}>
              Generate Video
            </ClipContextMenuItem>
          )}
          {props.hasBatchSelection && props.onDeleteClips ? (
            <ClipContextMenuItem
              icon={Trash2}
              onClick={() => { props.onDeleteClips?.(props.selectedClipIds); props.closeMenu(); }}
              destructive
              suffix={<span className="ml-auto text-xs tracking-widest opacity-60">Del</span>}
            >
              Delete {props.selectedClipIds.length} clips
            </ClipContextMenuItem>
          ) : props.onDeleteClip && (
            <ClipContextMenuItem
              icon={Trash2}
              onClick={() => { props.onDeleteClip?.(props.actionId); props.closeMenu(); }}
              destructive
              suffix={<span className="ml-auto text-xs tracking-widest opacity-60">Del</span>}
            >
              Delete Clip
            </ClipContextMenuItem>
          )}
        </>
      )}
    </div>,
    document.body,
  );
}

function ClipActionComponent({
  action,
  clipMeta,
  isSelected,
  isPrimary: _isPrimary = false,
  isInPinnedShotGroup = false,
  selectedClipIds = [],
  thumbnailSrc,
  onSelect,
  onDoubleClickAsset,
  onDoubleClickVideoClip,
  onSplitHere,
  onSplitClipsAtPlayhead,
  onDeleteClip,

import { useCallback, useRef } from 'react';
import { buildRowTrackPatches } from '@/tools/video-editor/lib/coordinate-utils';
import { getSourceTime, type ClipMeta, type TimelineData } from '@/tools/video-editor/lib/timeline-data';
import { resolveOverlaps } from '@/tools/video-editor/lib/resolve-overlaps';
import type { TimelineApplyEdit } from '@/tools/video-editor/hooks/timeline-state-types';
import type { TrackKind } from '@/tools/video-editor/types';
import type { TimelineAction, TimelineRow } from '@/tools/video-editor/types/timeline-canvas';

type ResizeDir = 'left' | 'right';

interface ResizeStartTarget {
  action: TimelineAction;
  row: TimelineRow;
  dir: ResizeDir;
}

interface ResizeEndTarget extends ResizeStartTarget {
  start: number;
  end: number;
}

interface ResizeStartState {
  start: number;
  from: number;
  to: number;
  speed: number;
  trackKind: TrackKind;
  assetDuration?: number;
}

export interface UseClipResizeArgs {
  dataRef: React.MutableRefObject<TimelineData | null>;
  applyEdit: TimelineApplyEdit;
}

export interface UseClipResizeResult {
  onActionResizeStart: (params: ResizeStartTarget & { adjacent?: ResizeStartTarget }) => void;
  onActionResizeEnd: (params: ResizeEndTarget & { adjacent?: ResizeEndTarget }) => void;
}

const getTrackKind = (
  current: TimelineData,
  rowId: string,
  fallbackTrackId?: string,
): TrackKind => {
  return current.tracks.find((track) => track.id === rowId)?.kind
    ?? current.tracks.find((track) => track.id === fallbackTrackId)?.kind
    ?? 'visual';
};

const getAssetDuration = (
  current: TimelineData,
  clipMeta: ClipMeta,
): number | undefined => {
  if (!clipMeta.asset) {
    return undefined;
  }

  return current.resolvedConfig.registry[clipMeta.asset]?.duration
    ?? current.registry.assets[clipMeta.asset]?.duration;
};

const getResolvedAction = (
  rows: TimelineRow[],
  rowId: string,
  actionId: string,
): TimelineAction | undefined => {
  return rows
    .find((candidate) => candidate.id === rowId)
    ?.actions.find((candidate) => candidate.id === actionId);
};

const getResizeStartState = (
  current: TimelineData,
  action: TimelineAction,
  row: TimelineRow,
  clipMeta: ClipMeta,
): ResizeStartState => {
  const from = clipMeta.from ?? 0;
  const speed = clipMeta.speed ?? 1;

  return {
    start: action.start,
    from,
    to: getSourceTime({ from, start: action.start, speed }, action.end),
    speed,
    trackKind: getTrackKind(current, row.id, clipMeta.track),
    assetDuration: getAssetDuration(current, clipMeta),
  };
};

const mergeMetaUpdates = (
  ...patchSets: Array<Record<string, Partial<ClipMeta>>>
): Record<string, Partial<ClipMeta>> => {
  const merged: Record<string, Partial<ClipMeta>> = {};

  for (const patchSet of patchSets) {
    for (const [clipId, patch] of Object.entries(patchSet)) {
      merged[clipId] = {
        ...merged[clipId],
        ...patch,
      };
    }
  }

  return merged;
};

export function useClipResize({
  dataRef,
  applyEdit,
}: UseClipResizeArgs): UseClipResizeResult {
  const resizeStartRef = useRef<Record<string, ResizeStartState>>({});
  const resizeTransactionIdRef = useRef<Record<string, string>>({});

  const computePerClipUpdate = useCallback((
    rowsInput: TimelineRow[],
    current: TimelineData,
    action: TimelineAction,
    row: TimelineRow,
    dir: ResizeDir,
    clipMeta: ClipMeta,
    origin: ResizeStartState,
  ) => {
    let clampedStart = action.start;
    let clampedEnd = action.end;
    if (origin.trackKind === 'audio') {
      if (dir === 'left') {
        const minStart = action.end - (origin.to / origin.speed);
        clampedStart = Math.max(action.start, minStart);
      } else if (typeof origin.assetDuration === 'number') {
        const maxEnd = action.start + Math.max(0, origin.assetDuration - origin.from) / origin.speed;
        clampedEnd = Math.min(action.end, maxEnd);
      }
    }

    const metaUpdates: Record<string, Partial<ClipMeta>> = {
      ...buildRowTrackPatches(rowsInput),
      [action.id]: {
        track: row.id,
      },
    };

    const nextRows = rowsInput.map((entry) => {
      if (entry.id !== row.id) {
        return entry;
      }

      return {
        ...entry,
        actions: entry.actions.map((candidate) => {
          return candidate.id === action.id
            ? { ...candidate, start: clampedStart, end: clampedEnd }
            : candidate;
        }),
      };
    });

    const { rows: resolvedRows, metaPatches: overlapPatches } = resolveOverlaps(
      nextRows, row.id, action.id, current.meta,
    );

    const resolvedAction = getResolvedAction(resolvedRows, row.id, action.id);
    const resolvedMetaUpdates = mergeMetaUpdates(metaUpdates, overlapPatches);

    if (resolvedAction && typeof clipMeta.hold !== 'number') {
      const resolvedStart = resolvedAction.start;
      const resolvedEnd = resolvedAction.end;
      const resolvedDuration = resolvedEnd - resolvedStart;

      if (resolvedDuration > 0) {
        if (origin.trackKind === 'visual') {
          if (dir === 'left') {
            const from = Math.max(0, origin.from + (resolvedStart - origin.start) * origin.speed);
            resolvedMetaUpdates[action.id] = {
              ...resolvedMetaUpdates[action.id],
              from,
              to: origin.to,
              speed: (origin.to - from) / resolvedDuration,
            };
          } else {
            resolvedMetaUpdates[action.id] = {
              ...resolvedMetaUpdates[action.id],
              from: origin.from,
              to: origin.to,
              speed: (origin.to - origin.from) / resolvedDuration,
            };
          }
        } else {
          const from = Math.max(0, origin.from + (resolvedStart - origin.start) * origin.speed);
          const unclampedTo = from + resolvedDuration * origin.speed;
          resolvedMetaUpdates[action.id] = {
            ...resolvedMetaUpdates[action.id],
            from,
            to: typeof origin.assetDuration === 'number'
              ? Math.min(origin.assetDuration, unclampedTo)
              : unclampedTo,
          };
        }
      }
    }

    return {
      rowsAfter: resolvedRows,
      metaUpdates: resolvedMetaUpdates,
    };
  }, []);

  const onActionResizeStart = useCallback(({ action, row, adjacent }: ResizeStartTarget & { adjacent?: ResizeStartTarget }) => {
    if (action.id.startsWith('uploading-')) return;
    const current = dataRef.current;
    const clipMeta = current?.meta[action.id];
    if (!current || !clipMeta || typeof clipMeta.hold === 'number') {
      return;
    }

    const transactionId = crypto.randomUUID();

    resizeStartRef.current[action.id] = getResizeStartState(current, action, row, clipMeta);
    resizeTransactionIdRef.current[action.id] = transactionId;

    if (!adjacent || adjacent.action.id.startsWith('uploading-')) {
      return;
    }

    const adjacentClipMeta = current.meta[adjacent.action.id];
    if (!adjacentClipMeta || typeof adjacentClipMeta.hold === 'number') {
      return;
    }

    resizeStartRef.current[adjacent.action.id] = getResizeStartState(current, adjacent.action, adjacent.row, adjacentClipMeta);
    resizeTransactionIdRef.current[adjacent.action.id] = transactionId;
  }, [dataRef]);

  const onActionResizeEnd = useCallback(({
    action,
    row,
    start,
    end,
    dir,
    adjacent,
  }: ResizeEndTarget & { adjacent?: ResizeEndTarget }) => {
    if (action.id.startsWith('uploading-')) return;
    const current = dataRef.current;
    const clipMeta = current?.meta[action.id];
    if (!current || !clipMeta) {
      return;
    }

    const resizedAction = {
      ...action,
      start,
      end,
    };
    const origin = resizeStartRef.current[action.id] ?? getResizeStartState(current, action, row, clipMeta);
    const primaryResult = computePerClipUpdate(
      current.rows,
      current,
      resizedAction,
      row,

      row,
      dir,
      clipMeta,
      origin,
    );

    let rowsAfter = primaryResult.rowsAfter;
    let metaUpdates = primaryResult.metaUpdates;

    if (adjacent && !adjacent.action.id.startsWith('uploading-')) {
      const adjacentClipMeta = current.meta[adjacent.action.id];
      if (adjacentClipMeta) {
        const adjacentOrigin = resizeStartRef.current[adjacent.action.id]
          ?? getResizeStartState(current, adjacent.action, adjacent.row, adjacentClipMeta);
        const adjacentAction = {
          ...adjacent.action,
          start: adjacent.start,
          end: adjacent.end,
        };
        const adjacentResult = computePerClipUpdate(
          rowsAfter,
          current,
          adjacentAction,
          adjacent.row,
          adjacent.dir,
          adjacentClipMeta,
          adjacentOrigin,
        );

        rowsAfter = adjacentResult.rowsAfter;
        metaUpdates = mergeMetaUpdates(metaUpdates, adjacentResult.metaUpdates);
      }
    }

    applyEdit({
      type: 'rows',
      rows: rowsAfter,
      metaUpdates,
    }, { transactionId: resizeTransactionIdRef.current[action.id] ?? crypto.randomUUID() });

    const idsToClear = adjacent ? [action.id, adjacent.action.id] : [action.id];
    for (const clipId of idsToClear) {
      delete resizeStartRef.current[clipId];
      delete resizeTransactionIdRef.current[clipId];
    }
  }, [applyEdit, computePerClipUpdate, dataRef]);

  return {
    onActionResizeStart,
    onActionResizeEnd,
  };
}
  onDeleteClip,
  onDeleteClips,
  onToggleMuteClips,
  isVideoClip,
  isTaskActive,
  isVariantStale,
  isGenerationAsset,
  onUpdateVariant,
  onDismissStale,
  canCreateShotFromSelection = false,
  existingShots,
  onCreateShotFromSelection,
  onGenerateVideoFromSelection,
  onNavigateToShot,
  onOpenGenerateVideo,
  isCreatingShot = false,
  audioSrc,
  clipWidth,
}: ClipActionProps) {
  const [contextMenu, setContextMenu] = useState<ContextMenuState | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);
  const openMenuWithSelectionRef = useRef<(clientX: number, clientY: number) => void>(() => undefined);
  const { waveform } = useWaveformData(audioSrc, {
    from: clipMeta.from,
    to: clipMeta.to,
    speed: clipMeta.speed,
    numBuckets: Math.max(2, Math.floor((clipWidth ?? 60) / 3)),
  });

  const closeMenu = useCallback(() => setContextMenu(null), []);
  const openMenuAt = useCallback((x: number, y: number) => { setContextMenu({ x, y, clientX: x }); }, []);

  useEffect(() => {
    if (!contextMenu) return;
    const handleClickOutside = (e: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(e.target as Node)) {
        closeMenu();
      }
    };
    const handleEscape = (e: KeyboardEvent) => {
      if (e.key === 'Escape') closeMenu();
    };
    document.addEventListener('mousedown', handleClickOutside);
    document.addEventListener('keydown', handleEscape);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
      document.removeEventListener('keydown', handleEscape);
    };
  }, [contextMenu, closeMenu]);

  openMenuWithSelectionRef.current = (clientX: number, clientY: number) => {
    if (!isSelected) {
      onSelect(action.id, clipMeta.track);
      requestAnimationFrame(() => openMenuAt(clientX, clientY));
      return;
    }

    openMenuAt(clientX, clientY);
  };

  const isEffectLayer = clipMeta.clipType === 'effect-layer';
  const icon = isEffectLayer
    ? <Layers className="h-3 w-3" />
    : clipMeta.clipType === 'text'
    ? <Type className="h-3 w-3" />
    : clipMeta.track.startsWith('A')
      ? <Music2 className="h-3 w-3" />
      : isVideoClip
        ? <Film className="h-3 w-3" />
        : <ImageIcon className="h-3 w-3" />;
  const hasBatchSelection = isSelected && selectedClipIds.length > 1;
  const hasPinnedShotGroupAssetActions = !hasBatchSelection && Boolean(
    (isGenerationAsset && onUpdateVariant)
    || (isVariantStale && onDismissStale),
  );
  const handleContextMenu = useCallback((e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (isInPinnedShotGroup && !hasPinnedShotGroupAssetActions) {
      return;
    }
    const { clientX, clientY } = e;
    openMenuWithSelectionRef.current(clientX, clientY);
  }, [hasPinnedShotGroupAssetActions, isInPinnedShotGroup]);
  const showShotActions = canCreateShotFromSelection && (
    typeof onCreateShotFromSelection === 'function' || typeof onGenerateVideoFromSelection === 'function'
  );
  const hasActionsBeforeShotSection = (
    (!hasBatchSelection && isGenerationAsset && onUpdateVariant)
    || (!hasBatchSelection && isVariantStale && onDismissStale)
    || (!hasBatchSelection && onSplitHere)
    || (hasBatchSelection && onToggleMuteClips)
    || (hasBatchSelection && onSplitClipsAtPlayhead)
  );
  const effectBadges = [clipMeta.entrance?.type ? `In:${clipMeta.entrance.type}` : null, clipMeta.continuous?.type ? `Loop:${clipMeta.continuous.type}` : null, clipMeta.exit?.type ? `Out:${clipMeta.exit.type}` : null].filter(Boolean);

  return (
    <>
      <button
        type="button"
        className={cn(
          'clip-action group relative flex h-full w-full overflow-hidden rounded-md border text-left',
          isEffectLayer && isSelected
            ? 'border-violet-400 bg-violet-500/20 text-violet-50'
            : isEffectLayer
              ? 'border-violet-500/30 bg-violet-500/10 text-violet-300 hover:border-violet-400/60'
