  const positionedShotGroups = useMemo(() => {
    const snapThresholdSeconds = SNAP_THRESHOLD_PX / pixelsPerSecond;

    return shotGroups.flatMap<PositionedShotGroup>((group) => {
      const row = rows[group.rowIndex];
      if (!row || row.id !== group.rowId) {
        return [];
