    setResizeClampedActionId((current) => (
      resizeClamped
        ? session.actionId
        : current === session.actionId
          ? null
          : current
    ));
    onActionResizing?.({
      action: nextAction,
      row: context.row,
      start,
      end,
      dir: session.dir,
    });
  }, [getResizeContext, minDuration, onActionResizing, pixelsPerSecond, rows]);

  const endResize = useCallback((event: ReactPointerEvent<HTMLDivElement>, cancelled: boolean) => {
    const session = resizeSessionRef.current;
    if (!session || session.pointerId !== event.pointerId) {
      return;
    }

    resizeSessionRef.current = null;
    if (event.currentTarget.hasPointerCapture(event.pointerId)) {
      event.currentTarget.releasePointerCapture(event.pointerId);
    }

    pendingOpsRef.current -= 1;
    setResizeClampedActionId((current) => (current === session.actionId ? null : current));
    const context = getResizeContext(session.actionId, session.rowId);
    const adjacentContext = session.adjacent
      ? getResizeContext(session.adjacent.actionId, session.adjacent.rowId)
      : null;
    if (!cancelled && context) {
      onActionResizeEnd?.({
        action: context.action,
        row: context.row,
        start: context.action.start,
        end: context.action.end,
        dir: session.dir,
        adjacent: adjacentContext ? {
          action: adjacentContext.action,
          row: adjacentContext.row,
          start: adjacentContext.action.start,
          end: adjacentContext.action.end,
          dir: session.adjacent!.dir,
        } : undefined,
      });
    }

    clearResizeOverride(session.actionId);
    if (session.adjacent) {
      clearResizeOverride(session.adjacent.actionId);
    }
