  const handleResizePointerDown = useCallback((
    event: ReactPointerEvent<HTMLDivElement>,
    action: TimelineAction,
    row: TimelineRow,
    dir: ResizeDir,
  ) => {
    if (event.button !== 0) {
      return;
    }

    const resizeLimits = getAudioResizeLimits(dataRef.current, action, row, dir);
    const adjacent = getShotGroupAdjacent(action, row, dir);
    const adjacentAction = adjacent
      ? row.actions.find((candidate) => candidate.id === adjacent.actionId)
      : undefined;
    resizeSessionRef.current = {
      pointerId: event.pointerId,
      actionId: action.id,
      rowId: row.id,
      dir,
      initialStart: action.start,
      initialEnd: action.end,
      initialClientX: event.clientX,
      adjacent,
      ...resizeLimits,
    };
