      start: action.start,
      end: action.end,
    };
    if (adjacent) {
      resizePreviewRef.current[adjacent.actionId] = {
        start: adjacent.initialStart,
        end: adjacent.initialEnd,
      };
    }
    setResizeClampedActionId(null);
    setResizeOverrides((current) => ({
      ...current,
      [action.id]: {
        start: action.start,
        end: action.end,
      },
      ...(adjacent ? {
        [adjacent.actionId]: {
          start: adjacent.initialStart,
          end: adjacent.initialEnd,
        },
      } : {}),
    }));
