    { id: 'clip-1', start: 0, end: 1, effectId: 'effect-clip-1' },
    { id: 'clip-2', start: 1, end: 2, effectId: 'effect-clip-2' },
    { id: 'clip-3', start: 2, end: 3, effectId: 'effect-clip-3' },
  ],
};
const shiftedPinnedGroupRow: TimelineRow = {
  id: 'V1',
