      row: pinnedGroupRow,
      actionId: 'clip-2',
      shotGroups: [pinnedShotGroup],
    });

    fireEvent.pointerDown(leftHandle, {
      button: 0,
      pointerId: 11,
      clientX: 200,
    });

    fireEvent.pointerMove(leftHandle, {
      pointerId: 11,
      clientX: 250,
    });

    fireEvent.pointerUp(leftHandle, {
      pointerId: 11,
      clientX: 250,
    });

    expect(onActionResizeStart).toHaveBeenCalledTimes(1);
    expect(onActionResizeStart).toHaveBeenCalledWith(expect.objectContaining({
      action: expect.objectContaining({ id: 'clip-2' }),
      dir: 'left',
      adjacent: expect.objectContaining({
        action: expect.objectContaining({ id: 'clip-1' }),
        dir: 'right',
      }),
    }));

    expect(onActionResizeEnd).toHaveBeenCalledTimes(1);
    const resizeEndCall = onActionResizeEnd.mock.calls[0]?.[0];
    expect(resizeEndCall).toMatchObject({
      action: expect.objectContaining({ id: 'clip-2' }),
      dir: 'left',
      adjacent: expect.objectContaining({
        action: expect.objectContaining({ id: 'clip-1' }),
        dir: 'right',
      }),
    });
    expect(resizeEndCall.start).toBe(1.5);
    expect(resizeEndCall.adjacent.end).toBe(1.5);
  });

